                    <img src='media/images/largestBroker.svg'></img>
                </div>
                <div className='col-6 mt-5'>
                    <h1>Largest Stock brocker in India</h1>
                    <p> That's why 1.6+ crore customers trust Zerodha with ~ ₹6 lakh crores of equity investments</p>
                    <ul>
                        <li>profit</li>
                        <li>future</li>
                        <li>Good</li>
                    </ul>
                </div>
            </div>
        </div>
    );
}

export default Awards;
